#include "block_chain.h"
__declspec(dllexport) void run(void) { CvmState*s=cvm_state(); H target,call_h,out; cvm_pop(target); cvm_zero(out); if(s&&s->payload_len>=32){u8 buf[68]; memcpy(buf,s->payload,32);buf[32]=36;buf[33]=0;buf[34]=0;buf[35]=0;memcpy(buf+36,target,32);block_write(buf,68,call_h); u32 clen=0,ilen=0;u8*chain=block_read(s->view_hash,&clen);u8*item=block_read(call_h,&ilen);if(chain&&item){bc_save_edit(chain,clen,item,ilen,0,0,out);memcpy(s->view_hash,out,32);}if(chain)free(chain);if(item)free(item);} cnext(); }
